service/ReservationService.java에 @Transactional complete(String userId, String reservationId)·cancel(String userId, String reservationId) 추가. 공통: Reservation r = reservationMapper.findById(id); if(r==null || !r.getUserId().equals(userId)) throw new ResponseStatusException(HttpStatus.NOT_FOUND, "예약을 찾을 수 없습니다."); 
 complete: r.complete(); reservationMapper.updateStatus(id, r.getStatus().name()); Slot s=slotMapper.findByKey(r.getStoreId(),r.getBayId(),r.getDate(),r.getTimeSlot()); if(s!=null){ s.complete(); slotMapper.updateStatusWithVersion(s.getId(), s.getStatus().name(), s.getVersion()); } 
 cancel: r.cancel(); reservationMapper.updateStatus(id, r.getStatus().name()); Slot s=slotMapper.findByKey(...); if(s!=null){ s.release(); slotMapper.updateStatusWithVersion(s.getId(), s.getStatus().name(), s.getVersion()); } 
 import org.springframework.web.bind.annotation 대신 org.springframework.web.server.ResponseStatusException, org.springframework.http.HttpStatus. 
 exception/GlobalExceptionHandler.java: @ExceptionHandler(IllegalStateException.class) → 409 ErrorResponse("INVALID_TRANSITION", e.getMessage()).

controller/ReservationController.java: import PatchMapping, PathVariable. 
 @PatchMapping("/{id}/complete") @ResponseStatus(HttpStatus.NO_CONTENT) public void complete(@AuthenticationPrincipal String userId, @PathVariable String id){ reservationService.complete(userId, id); } 
 @PatchMapping("/{id}/cancel") @ResponseStatus(HttpStatus.NO_CONTENT) public void cancel(@AuthenticationPrincipal String userId, @PathVariable String id){ reservationService.cancel(userId, id); } 
 /api/reservations/** 는 SecurityConfig anyRequest().authenticated()로 자동 보호(별도 설정 불필요).
